<?php
require_once __DIR__ . "/../config/config.php";

function redirect()
{
  $redirect = BASE;
  if (isset($_GET["redirect"]) && preg_match("#^" . BASE . ".*$#", $_GET["redirect"])) {
    $redirect = $_GET["redirect"];
  }
  header("Location: $redirect");
  die;
}

$failed = false;

if ($_SERVER["REQUEST_METHOD"] === "GET") {
  if (
    !SITE_PASSWORD ||
    ($_COOKIE["password"] ?? "") === hash("sha256", SITE_PASSWORD)
  ) {
    redirect();
  }
} else if ($_SERVER["REQUEST_METHOD"] === "POST") {
  if (!SITE_PASSWORD) {
    http_response_code(500);
    die;
  }

  if (($_POST["password"] ?? "") === SITE_PASSWORD) {
    setcookie("password", hash("sha256", SITE_PASSWORD), [
      "expires" => strtotime("+1 year"),
      "path" => BASE,
      "secure" => true,
      "httponly" => true,
      "samesite" => "Lax",
    ]);
    redirect();
  } else {
    $failed = true;
  }
}

if (CLASSIC_UI) {
  require_once __DIR__ . "/classic/login.php";
  die;
}
